class Solution:
    def smallestNumber(self, pattern: str) -> str:
        digits = list(range(1, 10))
        result = []
        i = 0
        while i < len(pattern):
            if pattern[i] == 'I':
                result.append(digits.pop(0))
            else:
                result.append(digits.pop())
            i += 1
        return ''.join(result)
